//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageacctestimport("crypto/ecdsa""crypto/elliptic""crypto/md5""crypto/rand""crypto/rsa""crypto/sha1""crypto/x509""crypto/x509/pkix""encoding/hex""encoding/pem""math/big""strings""testing""time")const(PEMBlockTypeCertificate=`CERTIFICATE`PEMBlockTypeCertificateRequest=`CERTIFICATEREQUEST`PEMBlockTypeECPrivateKey=`ECPRIVATEKEY`PEMBlockTypeRSAPrivateKey=`RSAPRIVATEKEY`PEMBlockTypePublicKey=`PUBLICKEY`)var(tlsX509CertificateSerialNumberLimit=new(big.Int).Lsh(big.NewInt(1),128)//nolint:gomnd)//TLSPEMRemovePublicKeyEncapsulationBoundariesremovespublickey//preandpostencapsulationboundariesfromaPEMstring.PEMRemovePublicKeyEncapsulationBoundaries(pemstring)string{returnremovePEMEncapsulationBoundaries(pem,PEMBlockTypePublicKey)}ovePEMEncapsulationBoundaries(pem,labelstring)string{returnstrings.ReplaceAll(strings.ReplaceAll(pem,pemPreEncapsulationBoundary(label),""),pemPostEncapsulationBoundary(label),"")}//Seehttps://www.rfc-editor.org/rfc/rfc7468#section-2.PreEncapsulationBoundary(labelstring)string{return`-----BEGIN`+label+`-----`}PostEncapsulationBoundary(labelstring)string{return`-----END`+label+`-----`}//TLSECDSAPublicKeyPEMgeneratesanECDSAprivatekeyPEMstringusingthespecifiedellipticcurve.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:private_key_pem="%[1]s"ECDSAPrivateKeyPEM(t*testing.T,curveNamestring)string{curve:=ellipticCurveForName(curveName)ifcurve==nil{t.Fatalf("unsupportedellipticcurve:%s",curveName)}key,err:=ecdsa.GenerateKey(elliptic.P384(),rand.Reader)iferr!=nil{t.Fatal(err)}bytes,err:=x509.MarshalECPrivateKey(key)iferr!=nil{t.Fatal(err)}block:=&pem.Block{Bytes:bytes,Type:PEMBlockTypeECPrivateKey,}returnstring(pem.EncodeToMemory(block))}//TLSECDSAPublicKeyPEMgeneratesanECDSApublickeyPEMstringandfingerprint.ECDSAPublicKeyPEM(t*testing.T,keyPemstring)(string,string){keyBlock,_:=pem.Decode([]byte(keyPem))key,err:=x509.ParseECPrivateKey(keyBlock.Bytes)iferr!=nil{t.Fatal(err)}publicKeyBytes,err:=x509.MarshalPKIXPublicKey(&key.PublicKey)iferr!=nil{t.Fatal(err)}block:=&pem.Block{Bytes:publicKeyBytes,Type:PEMBlockTypePublicKey,}md5sum:=md5.Sum(publicKeyBytes)hexarray:=make([]string,len(md5sum))fori,c:=rangemd5sum{hexarray[i]=hex.EncodeToString([]byte{c})}returnstring(pem.EncodeToMemory(block)),strings.Join(hexarray,":")}//TLSRSAPrivateKeyPEMgeneratesaRSAprivatekeyPEMstring.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:private_key_pem="%[1]s"RSAPrivateKeyPEM(t*testing.T,bitsint)string{key,err:=rsa.GenerateKey(rand.Reader,bits)iferr!=nil{t.Fatal(err)}block:=&pem.Block{Bytes:x509.MarshalPKCS1PrivateKey(key),Type:PEMBlockTypeRSAPrivateKey,}returnstring(pem.EncodeToMemory(block))}//TLSRSAPublicKeyPEMgeneratesaRSApublickeyPEMstring.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:public_key_pem="%[1]s"RSAPublicKeyPEM(t*testing.T,keyPemstring)string{keyBlock,_:=pem.Decode([]byte(keyPem))key,err:=x509.ParsePKCS1PrivateKey(keyBlock.Bytes)iferr!=nil{t.Fatal(err)}publicKeyBytes,err:=x509.MarshalPKIXPublicKey(&key.PublicKey)iferr!=nil{t.Fatal(err)}block:=&pem.Block{Bytes:publicKeyBytes,Type:PEMBlockTypePublicKey,}returnstring(pem.EncodeToMemory(block))}//TLSRSAX509LocallySignedCertificatePEMgeneratesalocalCAx509certificatePEMstring.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:certificate_pem="%[1]s"RSAX509LocallySignedCertificatePEM(t*testing.T,caKeyPem,caCertificatePem,keyPem,commonNamestring)string{caCertificateBlock,_:=pem.Decode([]byte(caCertificatePem))caCertificate,err:=x509.ParseCertificate(caCertificateBlock.Bytes)iferr!=nil{t.Fatal(err)}caKeyBlock,_:=pem.Decode([]byte(caKeyPem))caKey,err:=x509.ParsePKCS1PrivateKey(caKeyBlock.Bytes)iferr!=nil{t.Fatal(err)}keyBlock,_:=pem.Decode([]byte(keyPem))key,err:=x509.ParsePKCS1PrivateKey(keyBlock.Bytes)iferr!=nil{t.Fatal(err)}serialNumber,err:=rand.Int(rand.Reader,tlsX509CertificateSerialNumberLimit)iferr!=nil{t.Fatal(err)}certificate:=&x509.Certificate{BasicConstraintsValid:true,ExtKeyUsage:[]x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},KeyUsage:x509.KeyUsageDigitalSignature|x509.KeyUsageKeyEncipherment,NotAfter:time.Now().Add(24*time.Hour),//nolint:gomndNotBefore:time.Now(),SerialNumber:serialNumber,Subject:pkix.Name{CommonName:commonName,Organization:[]string{"ACMEExamples,Inc"},},}certificateBytes,err:=x509.CreateCertificate(rand.Reader,certificate,caCertificate,&key.PublicKey,caKey)iferr!=nil{t.Fatal(err)}certificateBlock:=&pem.Block{Bytes:certificateBytes,Type:PEMBlockTypeCertificate,}returnstring(pem.EncodeToMemory(certificateBlock))}//TLSRSAX509SelfSignedCACertificatePEMgeneratesax509CAcertificatePEMstring.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:root_certificate_pem="%[1]s"RSAX509SelfSignedCACertificatePEM(t*testing.T,keyPemstring)string{keyBlock,_:=pem.Decode([]byte(keyPem))key,err:=x509.ParsePKCS1PrivateKey(keyBlock.Bytes)iferr!=nil{t.Fatal(err)}publicKeyBytes,err:=x509.MarshalPKIXPublicKey(&key.PublicKey)iferr!=nil{t.Fatal(err)}publicKeyBytesSha1:=sha1.Sum(publicKeyBytes)serialNumber,err:=rand.Int(rand.Reader,tlsX509CertificateSerialNumberLimit)iferr!=nil{t.Fatal(err)}certificate:=&x509.Certificate{BasicConstraintsValid:true,ExtKeyUsage:[]x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},IsCA:true,KeyUsage:x509.KeyUsageDigitalSignature|x509.KeyUsageKeyEncipherment,NotAfter:time.Now().Add(24*time.Hour),//nolint:gomndNotBefore:time.Now(),SerialNumber:serialNumber,Subject:pkix.Name{CommonName:"ACMERootCA",Organization:[]string{"ACMEExamples,Inc"},},SubjectKeyId:publicKeyBytesSha1[:],}certificateBytes,err:=x509.CreateCertificate(rand.Reader,certificate,certificate,&key.PublicKey,key)iferr!=nil{t.Fatal(err)}certificateBlock:=&pem.Block{Bytes:certificateBytes,Type:PEMBlockTypeCertificate,}returnstring(pem.EncodeToMemory(certificateBlock))}//TLSRSAX509SelfSignedCACertificateForRolesAnywhereTrustAnchorPEMgeneratesax509CAcertificatePEMstring.//TheCAcertificateissuitableforuseasanIAMRolesAnywhereTrustAnchor.//Seehttps://docs.aws.amazon.com/rolesanywhere/latest/userguide/trust-model.html#signature-verification.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:root_certificate_pem="%[1]s"RSAX509SelfSignedCACertificateForRolesAnywhereTrustAnchorPEM(t*testing.T,keyPemstring)string{keyBlock,_:=pem.Decode([]byte(keyPem))key,err:=x509.ParsePKCS1PrivateKey(keyBlock.Bytes)iferr!=nil{t.Fatal(err)}publicKeyBytes,err:=x509.MarshalPKIXPublicKey(&key.PublicKey)iferr!=nil{t.Fatal(err)}publicKeyBytesSha1:=sha1.Sum(publicKeyBytes)serialNumber,err:=rand.Int(rand.Reader,tlsX509CertificateSerialNumberLimit)iferr!=nil{t.Fatal(err)}certificate:=&x509.Certificate{BasicConstraintsValid:true,ExtKeyUsage:[]x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},IsCA:true,KeyUsage:x509.KeyUsageDigitalSignature|x509.KeyUsageCertSign|x509.KeyUsageCRLSign,NotAfter:time.Now().Add(24*time.Hour),//nolint:gomndNotBefore:time.Now(),SerialNumber:serialNumber,SignatureAlgorithm:x509.SHA256WithRSA,Subject:pkix.Name{CommonName:"ACMERootCA",Organization:[]string{"ACMEExamples,Inc"},},SubjectKeyId:publicKeyBytesSha1[:],}certificateBytes,err:=x509.CreateCertificate(rand.Reader,certificate,certificate,&key.PublicKey,key)iferr!=nil{t.Fatal(err)}certificateBlock:=&pem.Block{Bytes:certificateBytes,Type:PEMBlockTypeCertificate,}returnstring(pem.EncodeToMemory(certificateBlock))}//TLSRSAX509SelfSignedCertificatePEMgeneratesax509certificatePEMstring.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:private_key_pem="%[1]s"RSAX509SelfSignedCertificatePEM(t*testing.T,keyPem,commonNamestring)string{keyBlock,_:=pem.Decode([]byte(keyPem))key,err:=x509.ParsePKCS1PrivateKey(keyBlock.Bytes)iferr!=nil{t.Fatal(err)}serialNumber,err:=rand.Int(rand.Reader,tlsX509CertificateSerialNumberLimit)iferr!=nil{t.Fatal(err)}certificate:=&x509.Certificate{BasicConstraintsValid:true,ExtKeyUsage:[]x509.ExtKeyUsage{x509.ExtKeyUsageServerAuth},KeyUsage:x509.KeyUsageDigitalSignature|x509.KeyUsageKeyEncipherment,NotAfter:time.Now().Add(24*time.Hour),//nolint:gomndNotBefore:time.Now(),SerialNumber:serialNumber,Subject:pkix.Name{CommonName:commonName,Organization:[]string{"ACMEExamples,Inc"},},}certificateBytes,err:=x509.CreateCertificate(rand.Reader,certificate,certificate,&key.PublicKey,key)iferr!=nil{t.Fatal(err)}certificateBlock:=&pem.Block{Bytes:certificateBytes,Type:PEMBlockTypeCertificate,}returnstring(pem.EncodeToMemory(certificateBlock))}//TLSRSAX509CertificateRequestPEMgeneratesax509certificaterequestPEMstring//andaRSAprivatekeyPEMstring.//WrapwithTLSPEMEscapeNewlines()toallowsimplefmt.Sprintf()//configurationssuchas:certificate_signing_request_pem="%[1]s"private_key_pem="%[2]s"RSAX509CertificateRequestPEM(t*testing.T,keyBitsint,commonNamestring)(string,string){keyBytes,err:=rsa.GenerateKey(rand.Reader,keyBits)iferr!=nil{t.Fatal(err)}csr:=x509.CertificateRequest{Subject:pkix.Name{CommonName:commonName,Organization:[]string{"ACMEExamples,Inc"},},SignatureAlgorithm:x509.SHA256WithRSA,}csrBytes,err:=x509.CreateCertificateRequest(rand.Reader,&csr,keyBytes)iferr!=nil{t.Fatal(err)}csrBlock:=&pem.Block{Bytes:csrBytes,Type:PEMBlockTypeCertificateRequest,}keyBlock:=&pem.Block{Bytes:x509.MarshalPKCS1PrivateKey(keyBytes),Type:PEMBlockTypeRSAPrivateKey,}returnstring(pem.EncodeToMemory(csrBlock)),string(pem.EncodeToMemory(keyBlock))}PEMEscapeNewlines(pemstring)string{returnstrings.ReplaceAll(pem,"\n","\\n")}PEMRemoveNewlines(pemstring)string{returnstrings.ReplaceAll(pem,"\n","")}ipticCurveForName(namestring)elliptic.Curve{switchname{case"P-224":returnelliptic.P224()case"P-256":returnelliptic.P256()case"P-384":returnelliptic.P384()case"P-521":returnelliptic.P521()}returnnil}